 1	import React, { FC } from 'react';
 2	
 3	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 4	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 5	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 6	
 7	import { onSubmitYAML } from '../details/utils/utils';
 8	import { ConfigurationInnerTabProps } from '../utils/types';
 9	
10	import SchedulingSection from './components/SchedulingSection';
11	
12	const SchedulingTab: FC<ConfigurationInnerTabProps> = ({ instanceTypeVM, vm, vmi }) => (
13	  <SidebarEditor
14	    onResourceUpdate={onSubmitYAML}
15	    pathsToHighlight={PATHS_TO_HIGHLIGHT.SCHEDULING_TAB}
16	    resource={vm}
17	  >
18	    {(resource) => (
19	      <PageSection variant={PageSectionVariants.light}>
20	        <SchedulingSection instanceTypeVM={instanceTypeVM} vm={resource} vmi={vmi} />
21	      </PageSection>
22	    )}
23	  </SidebarEditor>
24	);
25	
26	export default SchedulingTab;

